def get_current_user_id():
    try:
        user_response = supabase.auth.get_user(session["access_token"])  # Synchronous call
        if user_response and user_response.user:
            return user_response.user.id
        else:
            print("User is not authenticated.")  # Add logging for better debugging
            return None
    except Exception as e:
        print(f"Error getting user: {e}")
        
        return None
def CreateGuild():
    # Retrieve the guild name from the Entry widget
    guild_name = entry_1.get()

    # Check if the guild already exists in the 'Guilds' table
    response = supabase.table('Guilds').select('name', 'leader_id').eq('name', guild_name).execute()

    # If a guild with the same name exists, display an error message
    if response.data:
        subprocess.Popen(['python', 'Anime Version/Create Guild/error.py'])
    else:
        # If the guild doesn't exist, insert it into the table
        response = supabase.table('Guilds').insert({'name': guild_name, 'leader_id': get_current_user_id()}).execute()
        subprocess.Popen(['python', 'Anime Version/Create Guild/success.py'])
        ex_close(window)
